import{_ as a,o as t,c as e,a0 as o}from"./chunks/framework.Bmhw_dvp.js";const m=JSON.parse('{"title":"AI 平台","description":"","frontmatter":{},"headers":[],"relativePath":"aiAgents/ai.md","filePath":"aiAgents/ai.md"}'),i={name:"aiAgents/ai.md"};function n(l,r,h,s,g,p){return t(),e("div",null,[...r[0]||(r[0]=[o('<h1 id="ai-平台" tabindex="-1">AI 平台 <a class="header-anchor" href="#ai-平台" aria-label="Permalink to &quot;AI 平台&quot;">​</a></h1><p>当前主流的大语言模型与 AI 服务平台，按类型分为<strong>国际平台</strong>与<strong>国内平台</strong>。</p><hr><h2 id="国际平台" tabindex="-1">国际平台 <a class="header-anchor" href="#国际平台" aria-label="Permalink to &quot;国际平台&quot;">​</a></h2><h3 id="openai" tabindex="-1">OpenAI <a class="header-anchor" href="#openai" aria-label="Permalink to &quot;OpenAI&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://openai.com" target="_blank" rel="noreferrer">https://openai.com</a></li><li><strong>ChatGPT</strong>：<a href="https://chat.openai.com" target="_blank" rel="noreferrer">https://chat.openai.com</a></li><li><strong>API 文档</strong>：<a href="https://platform.openai.com/docs" target="_blank" rel="noreferrer">https://platform.openai.com/docs</a></li><li><strong>代表模型</strong>：GPT-4o、GPT-4、GPT-3.5-turbo、DALL·E、Whisper</li></ul><p>OpenAI 是全球领先的人工智能研究实验室，其 GPT 系列模型开创了大语言模型时代。</p><hr><h3 id="anthropic" tabindex="-1">Anthropic <a class="header-anchor" href="#anthropic" aria-label="Permalink to &quot;Anthropic&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://www.anthropic.com" target="_blank" rel="noreferrer">https://www.anthropic.com</a></li><li><strong>Claude</strong>：<a href="https://claude.ai" target="_blank" rel="noreferrer">https://claude.ai</a></li><li><strong>API 文档</strong>：<a href="https://docs.anthropic.com" target="_blank" rel="noreferrer">https://docs.anthropic.com</a></li><li><strong>代表模型</strong>：Claude 3.5 Sonnet、Claude 3 Opus、Claude 3 Haiku</li></ul><p>Anthropic 专注于 AI 安全与研究，Claude 以超长上下文和安全性著称。</p><hr><h3 id="google-deepmind" tabindex="-1">Google DeepMind <a class="header-anchor" href="#google-deepmind" aria-label="Permalink to &quot;Google DeepMind&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://deepmind.google" target="_blank" rel="noreferrer">https://deepmind.google</a></li><li><strong>Gemini</strong>：<a href="https://gemini.google.com" target="_blank" rel="noreferrer">https://gemini.google.com</a></li><li><strong>API 文档</strong>：<a href="https://ai.google.dev" target="_blank" rel="noreferrer">https://ai.google.dev</a></li><li><strong>代表模型</strong>：Gemini 1.5 Pro、Gemini 1.5 Flash、Gemini Ultra</li></ul><p>Google 的 Gemini 系列支持多模态理解，原生支持超长上下文窗口。</p><hr><h3 id="mistral-ai" tabindex="-1">Mistral AI <a class="header-anchor" href="#mistral-ai" aria-label="Permalink to &quot;Mistral AI&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://mistral.ai" target="_blank" rel="noreferrer">https://mistral.ai</a></li><li><strong>Le Chat</strong>：<a href="https://chat.mistral.ai" target="_blank" rel="noreferrer">https://chat.mistral.ai</a></li><li><strong>代表模型</strong>：Mistral Large、Mistral Medium、Mixtral 8x22B</li></ul><p>欧洲领先的 AI 公司，以开源模型和高效推理闻名。</p><hr><h3 id="cohere" tabindex="-1">Cohere <a class="header-anchor" href="#cohere" aria-label="Permalink to &quot;Cohere&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://cohere.com" target="_blank" rel="noreferrer">https://cohere.com</a></li><li><strong>代表模型</strong>：Command R、Command R+</li></ul><p>专注企业级应用和 RAG（检索增强生成）场景的模型提供商。</p><hr><h2 id="国内平台" tabindex="-1">国内平台 <a class="header-anchor" href="#国内平台" aria-label="Permalink to &quot;国内平台&quot;">​</a></h2><h3 id="百度文心一言" tabindex="-1">百度文心一言 <a class="header-anchor" href="#百度文心一言" aria-label="Permalink to &quot;百度文心一言&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://yiyan.baidu.com" target="_blank" rel="noreferrer">https://yiyan.baidu.com</a></li><li><strong>开发平台</strong>：<a href="https://qianfan.cloud.baidu.com" target="_blank" rel="noreferrer">https://qianfan.cloud.baidu.com</a></li><li><strong>代表模型</strong>：ERNIE Bot、ERNIE 4.0、ERNIE 3.5</li></ul><p>百度推出的知识增强大语言模型，在中文理解和知识问答方面表现突出。</p><hr><h3 id="阿里通义千问" tabindex="-1">阿里通义千问 <a class="header-anchor" href="#阿里通义千问" aria-label="Permalink to &quot;阿里通义千问&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://tongyi.aliyun.com" target="_blank" rel="noreferrer">https://tongyi.aliyun.com</a></li><li><strong>开源模型</strong>：<a href="https://github.com/QwenLM/Qwen" target="_blank" rel="noreferrer">https://github.com/QwenLM/Qwen</a></li><li><strong>代表模型</strong>：Qwen2.5、Qwen-VL、Qwen-Audio</li></ul><p>阿里巴巴开源的大模型系列，在国内外开发者社区广受欢迎。</p><hr><h3 id="字节豆包" tabindex="-1">字节豆包 <a class="header-anchor" href="#字节豆包" aria-label="Permalink to &quot;字节豆包&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://www.doubao.com" target="_blank" rel="noreferrer">https://www.doubao.com</a></li><li><strong>代表模型</strong>：Doubao-pro、Doubao-lite</li></ul><p>字节跳动推出的 AI 助手，在中文对话和内容创作上有较强能力。</p><hr><h3 id="智谱-ai-glm" tabindex="-1">智谱 AI（GLM） <a class="header-anchor" href="#智谱-ai-glm" aria-label="Permalink to &quot;智谱 AI（GLM）&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://www.zhipuai.cn" target="_blank" rel="noreferrer">https://www.zhipuai.cn</a></li><li><strong>ChatGLM</strong>：<a href="https://chatglm.cn" target="_blank" rel="noreferrer">https://chatglm.cn</a></li><li><strong>开源模型</strong>：<a href="https://github.com/THUDM/ChatGLM3" target="_blank" rel="noreferrer">https://github.com/THUDM/ChatGLM3</a></li><li><strong>代表模型</strong>：ChatGLM3、GLM-4</li></ul><p>清华系背景，GLM 架构在学术和工业界均有重要影响。</p><hr><h3 id="月之暗面-kimi" tabindex="-1">月之暗面（Kimi） <a class="header-anchor" href="#月之暗面-kimi" aria-label="Permalink to &quot;月之暗面（Kimi）&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://www.moonshot.cn" target="_blank" rel="noreferrer">https://www.moonshot.cn</a></li><li><strong>Kimi 智能助手</strong>：<a href="https://kimi.moonshot.cn" target="_blank" rel="noreferrer">https://kimi.moonshot.cn</a></li><li><strong>代表模型</strong>：Kimi k1.5</li></ul><p>以超长上下文窗口（200万字）著称，在文档理解和长文本处理上优势明显。</p><hr><h3 id="minimax" tabindex="-1">MiniMax <a class="header-anchor" href="#minimax" aria-label="Permalink to &quot;MiniMax&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://www.minimaxi.com" target="_blank" rel="noreferrer">https://www.minimaxi.com</a></li><li><strong>代表模型</strong>：abab6.5</li></ul><p>国内新兴的 AI 公司，提供文本、语音、视觉多模态能力。</p><hr><h3 id="讯飞星火" tabindex="-1">讯飞星火 <a class="header-anchor" href="#讯飞星火" aria-label="Permalink to &quot;讯飞星火&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://xinghuo.xfyun.cn" target="_blank" rel="noreferrer">https://xinghuo.xfyun.cn</a></li><li><strong>代表模型</strong>：讯飞星火认知大模型</li></ul><p>科大讯飞推出的认知大模型，在语音交互和教育场景有独特优势。</p>',52)])])}const u=a(i,[["render",n]]);export{m as __pageData,u as default};
